WebLink.url:
{!REQUIRESCRIPT("/soap/ajax/19.0/connection.js")} 
{!REQUIRESCRIPT("/soap/ajax/10.0/apex.js")}
var records = {!GETRECORDIDS($ObjectType.Contact)};
var url = parent.location.href;
if (records[0] == null) {
	alert("Please select at least one record to update.");
}else{

var username= sforce.apex.execute("UpdateKontakt","ausgabeUser",{nutzer:"PartnerPortal"});

var user = prompt ("Auf welchen Partnerbenutzer sollen die Kontakte geschlüsselt werden?\n\nBitte Vorname und und Nachname eingeben\n\n\n Folgende UserNamen können Sie angeben: \n\n" + username);

if(user != null){
var myvar = sforce.apex.execute("UpdateKontakt","updateKontakte", {kontaktID:records, userName:user, nutzer:"PartnerPortal"});
window.alert(myvar);
parent.location.href = url;
}
}
